+  private convertLemmaPOSTagToPartOfSpeech(
+    lemmaPOSTag: LemmaPOSTag
+  ): PartOfSpeech {
+    switch (lemmaPOSTag) {
+      case LemmaPOSTag.NOUN:
+        return new PartOfSpeech(PartOfSpeechType.NOUN);
+      case LemmaPOSTag.VERB:
